  1	import React, { FC } from 'react';
  2	
  3	import { Button, FormFieldGroupExpandable, FormFieldGroupHeader } from '@patternfly/react-core';
  4	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
  5	import { NetworkPolicy, NetworkPolicyRule } from '@utils/models';
  6	
  7	import { NetworkPolicyEgressIngress } from '../utils/types';
  8	import { emptyRule } from '../utils/utils';
  9	
 10	import NetworkPolicyRuleConfigPanel from './NetworkPolicyRuleConfigPanel/NetworkPolicyRuleConfigPanel';
 11	
 12	type NetworkPolicyFormIngressProps = {
 13	  networkPolicy: NetworkPolicy;
 14	  onPolicyChange: (policy: NetworkPolicy) => void;
 15	  removeAll: (msg: string, execute: () => void) => void;
 16	};
 17	
 18	const NetworkPolicyFormIngress: FC<NetworkPolicyFormIngressProps> = ({
 19	  networkPolicy,
 20	  onPolicyChange,
 21	  removeAll,
 22	}) => {
 23	  const { t } = useNetworkingTranslation();
 24	
 25	  if (networkPolicy.ingress.denyAll) return null;
 26	
 27	  const updateIngressRules = (rules: NetworkPolicyRule[]) =>
 28	    onPolicyChange({
 29	      ...networkPolicy,
 30	      ingress: { ...networkPolicy.ingress, rules },
 31	    });
 32	
 33	  const addIngressRule = () => {
 34	    updateIngressRules([emptyRule(), ...networkPolicy.ingress.rules]);
 35	  };
 36	
 37	  const removeAllIngress = () => {
 38	    removeAll(
 39	      t('This action will remove all rules within the Ingress section and cannot be undone.'),
 40	      () => updateIngressRules([]),
 41	    );
 42	  };
 43	
 44	  const removeIngressRule = (idx: number) => {
 45	    updateIngressRules([
 46	      ...networkPolicy.ingress.rules.slice(0, idx),
 47	      ...networkPolicy.ingress.rules.slice(idx + 1),
 48	    ]);
 49	  };
 50	  return (
 51	    <FormFieldGroupExpandable
 52	      className="co-create-networkpolicy__expandable-xl"
 53	      header={
 54	        <FormFieldGroupHeader
 55	          actions={
 56	            <>
 57	              <Button
 58	                data-test="remove-all-ingress"
 59	                isDisabled={networkPolicy.ingress.rules.length === 0}
 60	                onClick={removeAllIngress}
 61	                variant="link"
 62	              >
 63	                {t('Remove all')}
 64	              </Button>
 65	              <Button data-test="add-ingress" onClick={addIngressRule} variant="secondary">
 66	                {t('Add ingress rule')}
 67	              </Button>
 68	            </>
 69	          }
 70	          titleDescription={t(
 71	            'Add ingress rules to be applied to your selected pods. Traffic is allowed from pods if it matches at least one rule.',
 72	          )}
 73	          titleText={{
 74	            id: 'ingress-header',
 75	            text: t('Ingress'),
 76	          }}
 77	        />
 78	      }
 79	      isExpanded
 80	      toggleAriaLabel="Ingress"
 81	    >
 82	      {networkPolicy.ingress.rules.map((rule, idx) => (
 83	        <NetworkPolicyRuleConfigPanel
 84	          direction={NetworkPolicyEgressIngress.ingress}
 85	          key={rule.key}
 86	          onChange={(r) => {
 87	            const newRules = [...networkPolicy.ingress.rules];
 88	            newRules[idx] = r;
 89	            updateIngressRules(newRules);
 90	          }}
 91	          onRemove={() => removeIngressRule(idx)}
 92	          policyNamespace={networkPolicy.namespace}
 93	          rule={rule}
 94	        />
 95	      ))}
 96	    </FormFieldGroupExpandable>
 97	  );
 98	};
 99	
100	export default NetworkPolicyFormIngress;

